class ETGSalesInvoiceCashewController extends SrsReportRunController
{
    CustInvoiceJour             CustInvoiceJour;

}

Method.Source:
protected void prePromptModifyContract()
{
    ETGSalesInvoiceCashewContract         salesTaxInvoice;

    custInvoiceJour =    this.parmArgs().record();
    salesTaxInvoice   = this.parmReportContract().parmRdpContract() as ETGSalesInvoiceCashewContract;
   // salesTaxInvoice = this.parmReportContract().parmRdlContract().parmLanguageId('fr-FR') as salesTaxInvoice;
   // this.parmReportContract().parmRdlCOntract().parmLanguageId('fr-FR');
    salesTaxInvoice.parmRecid(custInvoiceJour.RecId);
}

public static ETGSalesInvoiceCashewController construct()
{
    return new ETGSalesInvoiceCashewController();
}

public static void main(Args _args)
{
    ETGSalesInvoiceCashewController salesTaxInvoice  = new ETGSalesInvoiceCashewController();
    salesTaxInvoice.parmArgs(_args);
    salesTaxInvoice.parmReportName(ssrsReportStr(ETGSalesInvoiceCashew, ETGSalesInvoiceCashew));
    salesTaxInvoice.parmShowDialog(false);
    salesTaxInvoice.startOperation();
}
